CREATE TYPE "FreeAccessApplicationStatus" AS ENUM ('ENABLED', 'DISABLED');
CREATE TABLE "free_access_wallets" ("id" TEXT NOT NULL, "wallet_address" TEXT NOT NULL, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "free_access_wallets_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_wallets_wallet_address_key" ON "free_access_wallets"("wallet_address");
CREATE TABLE "free_access_applications" ("id" TEXT NOT NULL, "wallet_id" TEXT NOT NULL, "name" TEXT NOT NULL, "scopes" JSONB NOT NULL DEFAULT '["matches:read"]', "status" "FreeAccessApplicationStatus" NOT NULL DEFAULT 'ENABLED', "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "free_access_applications_pkey" PRIMARY KEY ("id"));
CREATE INDEX "free_access_applications_wallet_id_status_idx" ON "free_access_applications"("wallet_id", "status");
CREATE TABLE "free_access_credentials" ("id" TEXT NOT NULL, "application_id" TEXT NOT NULL, "client_id" TEXT NOT NULL, "verifier" TEXT NOT NULL, "scopes" JSONB NOT NULL, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "revoked_at" TIMESTAMPTZ(3), CONSTRAINT "free_access_credentials_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_credentials_client_id_key" ON "free_access_credentials"("client_id");
CREATE INDEX "free_access_credentials_application_id_revoked_at_idx" ON "free_access_credentials"("application_id", "revoked_at");
CREATE TABLE "free_access_challenges" ("id" TEXT NOT NULL, "wallet_address" TEXT NOT NULL, "domain" TEXT NOT NULL, "uri" TEXT NOT NULL, "chain" TEXT NOT NULL, "nonce" TEXT NOT NULL, "issued_at" TIMESTAMPTZ(3) NOT NULL, "request_id" TEXT NOT NULL, "challenge_hash" TEXT NOT NULL, "expires_at" TIMESTAMPTZ(3) NOT NULL, "attempts" INTEGER NOT NULL DEFAULT 0, "consumed_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "free_access_challenges_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_challenges_challenge_hash_key" ON "free_access_challenges"("challenge_hash");
CREATE INDEX "free_access_challenges_wallet_address_expires_at_idx" ON "free_access_challenges"("wallet_address", "expires_at");
CREATE TABLE "free_access_quotas" ("id" TEXT NOT NULL, "application_id" TEXT NOT NULL, "quota_day" DATE NOT NULL, "used" INTEGER NOT NULL DEFAULT 0, "daily_limit" INTEGER NOT NULL, "updated_at" TIMESTAMPTZ(3) NOT NULL, CONSTRAINT "free_access_quotas_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_quotas_application_id_quota_day_key" ON "free_access_quotas"("application_id", "quota_day");
CREATE TABLE "free_access_sessions" ("id" TEXT NOT NULL, "wallet_id" TEXT NOT NULL, "session_hash" TEXT NOT NULL, "csrf_hash" TEXT NOT NULL, "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "last_seen_at" TIMESTAMPTZ(3) NOT NULL, "expires_at" TIMESTAMPTZ(3) NOT NULL, "revoked_at" TIMESTAMPTZ(3), CONSTRAINT "free_access_sessions_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_sessions_session_hash_key" ON "free_access_sessions"("session_hash");
CREATE INDEX "free_access_sessions_wallet_id_revoked_at_expires_at_idx" ON "free_access_sessions"("wallet_id", "revoked_at", "expires_at");
CREATE TABLE "free_access_tokens" ("id" TEXT NOT NULL, "application_id" TEXT NOT NULL, "token_hash" TEXT NOT NULL, "scopes" JSONB NOT NULL, "expires_at" TIMESTAMPTZ(3) NOT NULL, "revoked_at" TIMESTAMPTZ(3), "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "free_access_tokens_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "free_access_tokens_token_hash_key" ON "free_access_tokens"("token_hash");
CREATE INDEX "free_access_tokens_application_id_revoked_at_expires_at_idx" ON "free_access_tokens"("application_id", "revoked_at", "expires_at");
CREATE TABLE "free_access_audit_events" ("id" TEXT NOT NULL, "event_type" TEXT NOT NULL, "actor_pseudonym" TEXT, "route" TEXT, "success" BOOLEAN NOT NULL, "metadata" JSONB, "occurred_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "free_access_audit_events_pkey" PRIMARY KEY ("id"));
CREATE INDEX "free_access_audit_events_event_type_occurred_at_idx" ON "free_access_audit_events"("event_type", "occurred_at");
ALTER TABLE "free_access_applications" ADD CONSTRAINT "free_access_applications_wallet_id_fkey" FOREIGN KEY ("wallet_id") REFERENCES "free_access_wallets"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "free_access_credentials" ADD CONSTRAINT "free_access_credentials_application_id_fkey" FOREIGN KEY ("application_id") REFERENCES "free_access_applications"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "free_access_sessions" ADD CONSTRAINT "free_access_sessions_wallet_id_fkey" FOREIGN KEY ("wallet_id") REFERENCES "free_access_wallets"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
